mapper.insert:
INSERT INTO follow_up_monitoring_transfer_request (
    register_id, department_id, from_employee_id, to_employee_id, reason, status
) VALUES (
    #{registerId}, #{departmentId}, #{fromEmployeeId}, #{toEmployeeId}, #{reason}, 'pending'
)

mapper.select:
SELECT r.id, r.register_id AS "registerId", r.department_id AS "departmentId", r.from_employee_id AS "fromEmployeeId", fe.realname AS "fromEmployeeName", r.to_employee_id AS "toEmployeeId", te.realname AS "toEmployeeName", r.reason, r.status, r.created_at AS "createdAt", reg.real_name AS "patientName", reg.case_number AS "caseNumber" FROM follow_up_monitoring_transfer_request r JOIN register reg ON reg.id = r.register_id LEFT JOIN employee fe ON fe.id = r.from_employee_id LEFT JOIN employee te ON te.id = r.to_employee_id WHERE r.status = 'pending'
AND r.department_id = #{departmentId}
ORDER BY r.created_at ASC
